import { Avatar as AvatarPrimitive } from "@base-ui/react/avatar";
import { createStyleContext } from "@/registry/bare/lib/create-style-context";
import { createPropSplitter } from "@/registry/bare/lib/split-variant-props";
import { avatarStyles } from "./styles";
import type { VariantProps } from "@/registry/bare/lib/tv.config";

type AvatarStyles = ReturnType<typeof avatarStyles>;
type AvatarVariantProps = VariantProps<typeof avatarStyles>;

const { StyleContext, useStyles } =
  createStyleContext<AvatarStyles>("Avatar");
const splitProps = createPropSplitter(avatarStyles);

export { useStyles as useAvatarStyles };

interface AvatarRootProps
  extends AvatarPrimitive.Root.Props,
    AvatarVariantProps {
  className?: string;
  styles?: AvatarStyles;
}

export function AvatarRoot(props: AvatarRootProps) {
  const [variantProps, { className, styles, ...htmlProps }] = splitProps(
    props as Record<string, any>,
  );
  const s = styles ?? avatarStyles(variantProps);
  return (
    <StyleContext value={s}>
      <AvatarPrimitive.Root
        {...htmlProps}
        className={s.root({ class: className })}
        data-slot="avatar"
      />
    </StyleContext>
  );
}

import { Avatar as AvatarPrimitive } from "@base-ui/react/avatar";
import { useAvatarStyles } from "./avatar-root";

interface AvatarImageProps extends AvatarPrimitive.Image.Props {
  className?: string;
}

export function AvatarImage({ className, ...props }: AvatarImageProps) {
  const styles = useAvatarStyles();
  return (
    <AvatarPrimitive.Image
      {...props}
      className={styles.image({ class: className })}
      data-slot="avatar-image"
    />
  );
}

import { Avatar as AvatarPrimitive } from "@base-ui/react/avatar";
import { useAvatarStyles } from "./avatar-root";

interface AvatarFallbackProps extends AvatarPrimitive.Fallback.Props {
  className?: string;
}

export function AvatarFallback({
  className,
  ...props
}: AvatarFallbackProps) {
  const styles = useAvatarStyles();
  return (
    <AvatarPrimitive.Fallback
      {...props}
      className={styles.fallback({ class: className })}
      data-slot="avatar-fallback"
    />
  );
}

import { tv } from "@/registry/bare/lib/tv.config";

export const avatarStyles = tv({
  slots: {
    root: [""],
    image: [""],
    fallback: [""],
  },
});

export { AvatarRoot } from "./avatar-root";
export { AvatarImage } from "./avatar-image";
export { AvatarFallback } from "./avatar-fallback";

export { AvatarRoot as Avatar } from "./avatar-root";
export { AvatarImage } from "./avatar-image";
export { AvatarFallback } from "./avatar-fallback";
export { avatarStyles } from "./styles";
